describe('Matcher root path matching with zero-min wildcard spec', () => {
  it('spec "/**" should match both "/" and "/foo/bar"', () => {
    const matcher = Matcher.for('/**', '1.1')
    // The key: "/" must match
    // Original regex: ^/$|^(?:/[^/]+)*$  -- matches "/" via ^/$
    // Mutated regex: ^(?:/[^/]+)*$  -- does NOT match "/"
    const rootMatch = '/'.match(matcher)
    const deepMatch = '/foo/bar'.match(matcher)
    expect(rootMatch).not.toBeNull()
    expect(deepMatch).not.toBeNull()
  })
})
